class Solution:
    def popcountDepth(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        def popcount(x):
            return bin(x).count('1')

        def popcount_depth(x):
            d = 0
            while x != 1:
                x = popcount(x)
                d += 1
            return d

        depth = [popcount_depth(x) for x in nums]
        res = []
        for q in queries:
            if q[0] == 1:
                l, r, k = q[1], q[2], q[3]
                res.append(sum(1 for i in range(l, r+1) if depth[i] == k))
            else:
                idx, val = q[1], q[2]
                depth[idx] = popcount_depth(val)
        return res
```
